#!/usr/bin/env python3
import argparse
import socket
from collections import Counter, deque

from dnslib import A, CLASS, DNSRecord, QTYPE, RR

ROOT_SERVER_IP = "192.33.4.12"
ROOT_SERVER_PORT = 53
LISTEN_IP = "localhost"
LISTEN_PORT = 8000
BUFFER_SIZE = 8192
MAX_ITERATIONS = 32
SOCKET_TIMEOUT = 4.0
CACHE_WINDOW = 20
CACHE_SIZE = 3

# Cache state (only for client queries)
query_history = deque(maxlen=CACHE_WINDOW)
resolved_ips = {}
cache = {}
DEBUG = False


def normalize_name(name):
    text = str(name).strip().lower()
    if text in {"", "."}:
        return "."
    return text.rstrip(".") + "."


def display_name(name):
    text = normalize_name(name)
    return "." if text == "." else text.rstrip(".")


def debug_print(message):
    if DEBUG:
        print(message, flush=True)


def parse_dns_message(message_bytes):
    record = DNSRecord.parse(message_bytes)

    def rr_to_dict(rr):
        return {
            "name": str(rr.rname),
            "type": QTYPE[rr.rtype],
            "class": CLASS[rr.rclass],
            "ttl": rr.ttl,
            "rdata": str(rr.rdata),
        }

    return {
        "id": record.header.id,
        "qname": str(record.q.qname),
        "qtype": QTYPE[record.q.qtype],
        "qclass": CLASS[record.q.qclass],
        "ancount": record.header.a,
        "nscount": record.header.auth,
        "arcount": record.header.ar,
        "answer": [rr_to_dict(rr) for rr in record.rr],
        "authority": [rr_to_dict(rr) for rr in record.auth],
        "additional": [rr_to_dict(rr) for rr in record.ar],
    }


def extract_first_a_ip(record):
    for rr in record.rr:
        if rr.rtype == QTYPE.A:
            return str(rr.rdata)
    return None


def extract_a_ips_from_section(records):
    ips = []
    for rr in records:
        if rr.rtype == QTYPE.A:
            ips.append(str(rr.rdata))
    return ips


def extract_ns_names(record):
    names = []
    for rr in record.auth:
        if rr.rtype == QTYPE.NS:
            names.append(normalize_name(rr.rdata))
    return names


def send_dns_query(query_bytes, server_ip, server_port=ROOT_SERVER_PORT):
    sock = socket.socket(socket.AF_INET, socket.SOCK_DGRAM)
    sock.settimeout(SOCKET_TIMEOUT)
    try:
        sock.sendto(query_bytes, (server_ip, server_port))
        data, _ = sock.recvfrom(BUFFER_SIZE)
        return data
    finally:
        sock.close()


def build_a_response(query_record, ip_address):
    reply = query_record.reply()
    reply.add_answer(RR(rname=query_record.q.qname, rtype=QTYPE.A, rclass=CLASS.IN, ttl=60, rdata=A(ip_address)))
    return reply.pack()


def refresh_cache():
    global cache
    counts = Counter(query_history)
    top_domains = [domain for domain, _ in counts.most_common(CACHE_SIZE)]
    cache = {domain: resolved_ips[domain] for domain in top_domains if domain in resolved_ips}


def update_query_history(domain, ip_address):
    query_history.append(domain)
    resolved_ips[domain] = ip_address
    refresh_cache()


def resolve_name_to_ip(name):
    query_name = normalize_name(name)
    query_bytes = DNSRecord.question(query_name, qtype="A").pack()
    response_bytes = _resolve_query_recursive(query_bytes, query_name, ROOT_SERVER_IP, ".")
    if not response_bytes:
        return None

    try:
        response_record = DNSRecord.parse(response_bytes)
    except Exception:
        return None
    return extract_first_a_ip(response_record)


def _resolve_query_recursive(query_bytes, query_name, server_ip, server_name="."):
    current_ip = server_ip
    current_name = server_name
    visited_servers = set()

    for _ in range(MAX_ITERATIONS):
        normalized_query = display_name(query_name)
        debug_print(f"(debug) Consultando '{normalized_query}' a '{display_name(current_name)}' con dirección IP '{current_ip}'")

        if current_ip in visited_servers:
            return None
        visited_servers.add(current_ip)

        try:
            response_bytes = send_dns_query(query_bytes, current_ip)
        except (socket.timeout, OSError):
            return None

        try:
            response_record = DNSRecord.parse(response_bytes)
        except Exception:
            return response_bytes

        # If there is an A record in the Answer section, we are done.
        if extract_first_a_ip(response_record) is not None:
            return response_bytes

        # For non-delegation responses, return what we got.
        if response_record.header.rcode != 0:
            return response_bytes

        ns_names = extract_ns_names(response_record)
        additional_ips = extract_a_ips_from_section(response_record.ar)

        if additional_ips:
            current_ip = additional_ips[0]
            current_name = ns_names[0] if ns_names else current_name
            continue

        if ns_names:
            ns_name = ns_names[0]
            ns_ip = resolve_name_to_ip(ns_name)
            if ns_ip:
                current_ip = ns_ip
                current_name = ns_name
                continue

        return response_bytes

    return None


def resolver(mensaje_consulta):
    query_record = DNSRecord.parse(mensaje_consulta)
    qname = normalize_name(query_record.q.qname)

    if qname in cache:
        debug_print(f"(debug) Consulta '{display_name(qname)}' respondida desde caché con IP '{cache[qname]}'")
        return build_a_response(query_record, cache[qname])

    response_bytes = _resolve_query_recursive(mensaje_consulta, qname, ROOT_SERVER_IP, ".")
    if not response_bytes:
        return b""

    try:
        response_record = DNSRecord.parse(response_bytes)
    except Exception:
        return response_bytes

    ip_address = extract_first_a_ip(response_record)
    if ip_address:
        update_query_history(qname, ip_address)
    return response_bytes


def serve(debug=False):
    global DEBUG
    DEBUG = debug

    server_socket = socket.socket(socket.AF_INET, socket.SOCK_DGRAM)
    server_socket.bind((LISTEN_IP, LISTEN_PORT))
    print(f"Resolver escuchando en {LISTEN_IP}:{LISTEN_PORT}", flush=True)

    try:
        while True:
            message, client_address = server_socket.recvfrom(BUFFER_SIZE)
            print(message, flush=True)
            response = resolver(message)
            if response:
                server_socket.sendto(response, client_address)
    except KeyboardInterrupt:
        print("\nCerrando resolver...", flush=True)
    finally:
        server_socket.close()


def main():
    parser = argparse.ArgumentParser(description="Resolver DNS para la tarea")
    parser.add_argument("--debug", "-d", action="store_true", help="Muestra consultas internas")
    args = parser.parse_args()
    serve(debug=args.debug)


if __name__ == "__main__":
    main()

